"use strict";(self.webpackChunkdocusaurus_knowledge_base=self.webpackChunkdocusaurus_knowledge_base||[]).push([[98257],{39345(e,t,n){n.r(t),n.d(t,{assets:()=>c,contentTitle:()=>s,default:()=>f,frontMatter:()=>r,metadata:()=>i,toc:()=>d});let i=JSON.parse('{"id":"6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IAS 12 Income Taxes/multiple-tax-consequences-of-recover-83d524c0ea","title":"Multiple Tax Consequences of Recovering an Asset (IAS 12)","description":"April 2020","source":"@site/knowledge/6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IAS 12 Income Taxes/Multiple Tax Consequences of Recovering an Asset (IAS 12).md","sourceDirName":"6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IAS 12 Income Taxes","slug":"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-12-income-taxes-c46395e692/multiple-tax-consequences-of-recover-83d524c0ea","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-12-income-taxes-c46395e692/multiple-tax-consequences-of-recover-83d524c0ea","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":2,"frontMatter":{"id":"multiple-tax-consequences-of-recover-83d524c0ea","title":"Multiple Tax Consequences of Recovering an Asset (IAS 12)","slug":"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-12-income-taxes-c46395e692/multiple-tax-consequences-of-recover-83d524c0ea","sidebar_position":2},"sidebar":"knowledgeSidebar","previous":{"title":"Deferred Tax related to an Investment in a Subsidiary (IAS 12)","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-12-income-taxes-c46395e692/deferred-tax-related-to-an-investmen-2726c9fd48"},"next":{"title":"Attributing Benefit to Periods of Service (IAS 19)","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-19-employee-benefits-1c4dcadd93/attributing-benefit-to-periods-of-se-45abc7c877"}}');var a=n(74848),o=n(28453);let r={id:"multiple-tax-consequences-of-recover-83d524c0ea",title:"Multiple Tax Consequences of Recovering an Asset (IAS 12)",slug:"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-12-income-taxes-c46395e692/multiple-tax-consequences-of-recover-83d524c0ea",sidebar_position:2},s="Multiple Tax Consequences of Recovering an Asset (IAS 12)",c={},d=[{value:"The fundamental principle in IAS 12",id:"the-fundamental-principle-in-ias-12",level:2},{value:"Applying the fundamental principle to the fact pattern",id:"applying-the-fundamental-principle-to-the-fact-pattern",level:2}];function l(e){let t={h1:"h1",h2:"h2",header:"header",p:"p",...(0,o.R)(),...e.components};return(0,a.jsxs)(a.Fragment,{children:[(0,a.jsx)(t.header,{children:(0,a.jsx)(t.h1,{id:"multiple-tax-consequences-of-recovering-an-asset-ias-12",children:"Multiple Tax Consequences of Recovering an Asset (IAS 12)"})}),"\n",(0,a.jsx)(t.p,{children:"April 2020"}),"\n",(0,a.jsx)(t.p,{children:"The Committee received a request about deferred tax when the recovery of the carrying amount of an asset gives rise to multiple tax consequences. In the fact pattern described in the request:"}),"\n",(0,a.jsx)(t.p,{children:"a. an entity acquires an intangible asset with a finite useful life (a licence) as part of a business combination. The carrying amount of the licence at initial recognition is CU100. The entity intends to recover the carrying amount of the licence through use, and the expected residual value of the licence at expiry is nil.\nb. the applicable tax law prescribes two tax regimes: an income tax regime and a capital gains tax regime. Tax paid under both regimes meets the definition of income taxes in IAS 12. Recovering the licence\u2019s carrying amount has both of the following tax consequences:\ni. under the income tax regime\u2014the entity pays income tax on the economic benefits it receives from recovering the licence\u2019s carrying amount through use, but receives no tax deductions in respect of amortisation of the licence (taxable economic benefits from use); and\nii. under the capital gains tax regime\u2014the entity receives a tax deduction of CU100 when the licence expires (capital gain deduction).\nc. the applicable tax law prohibits the entity from using the capital gain deduction to offset the taxable economic benefits from use in determining taxable profit."}),"\n",(0,a.jsx)(t.p,{children:"The request asked how the entity determines the tax base of the asset and, consequently, how it recognises and measures deferred tax."}),"\n",(0,a.jsx)(t.h2,{id:"the-fundamental-principle-in-ias-12",children:"The fundamental principle in IAS 12"}),"\n",(0,a.jsx)(t.p,{children:"The fundamental principle upon which IAS 12 is based (as stated in paragraph 10 of IAS 12) is that \u2018an entity shall, with certain limited exceptions, recognise a deferred tax liability (asset) whenever recovery or settlement of the carrying amount of an asset or liability would make future tax payments larger (smaller) than they would be if such recovery or settlement were to have no tax consequences\u2019."}),"\n",(0,a.jsx)(t.h2,{id:"applying-the-fundamental-principle-to-the-fact-pattern",children:"Applying the fundamental principle to the fact pattern"}),"\n",(0,a.jsx)(t.p,{children:"The recovery of the asset\u2019s carrying amount gives rise to two distinct tax consequences\u2014it results in taxable economic benefits from use and a capital gain deduction that cannot be offset in determining taxable profit. Accordingly, applying the fundamental principle in IAS 12, an entity reflects separately these distinct tax consequences of recovering the asset\u2019s carrying amount."}),"\n",(0,a.jsx)(t.p,{children:"An entity identifies temporary differences in a manner that reflects these distinct tax consequences by comparing:\na. the portion of the asset\u2019s carrying amount that will be recovered under one tax regime; to\nb. the tax deductions the entity will receive under that same tax regime (which are reflected in the asset\u2019s tax base)."}),"\n",(0,a.jsx)(t.p,{children:"In the fact pattern described in the request, the Committee concluded that the entity identifies both:"}),"\n",(0,a.jsx)(t.p,{children:"a. a taxable temporary difference of CU100\u2014the entity will recover the licence\u2019s carrying amount (CU100) under the income tax regime, but will receive no tax deductions under that regime (that is, none of the tax base relates to deductions under the income tax regime); and\nb. a deductible temporary difference of CU100\u2014the entity will not recover any part of the licence\u2019s carrying amount under the capital gains tax regime, but will receive a deduction of CU100 upon expiry of the licence (that is, all of the tax base relates to deductions under the capital gains tax regime)."}),"\n",(0,a.jsx)(t.p,{children:"The entity then applies the requirements in IAS 12 considering the applicable tax law in recognising and measuring deferred tax for the identified temporary differences. The Committee concluded that the principles and requirements in IAS 12 provide an adequate basis for an entity to recognise and measure deferred tax in the fact pattern described in the request. Consequently, the Committee decided not to add the matter to its standard-setting agenda."})]})}function f(e={}){let{wrapper:t}={...(0,o.R)(),...e.components};return t?(0,a.jsx)(t,{...e,children:(0,a.jsx)(l,{...e})}):l(e)}},28453(e,t,n){n.d(t,{R:()=>r,x:()=>s});var i=n(96540);let a={},o=i.createContext(a);function r(e){let t=i.useContext(o);return i.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function s(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(a):e.components||a:r(e.components),i.createElement(o.Provider,{value:t},e.children)}}}]);